#include <bits/stdc++.h>
#define int long long
using namespace std;
struct Edge {
	int L , R , lz , sum;
}; 
Edge tr[400005];
int a[400005];
int n , m;
void build( int p , int L , int R ) {
	tr[p].L = L , tr[p].R = R , tr[p].sum = 0 , tr[p].lz = 0;
	if( L == R ) {
		return;
	}
	int mid = ( L + R ) / 2;
	build( p << 1 , L , mid );
	build( ( p << 1 ) + 1 , mid + 1 , R );
//	tr[p].sum = tr[p << 1].sum + tr[( p << 1 ) + 1].sum;
}
void uplz( int p ) {
	tr[p].lz ^= 1;
	tr[p].sum = tr[p].R - tr[p].L + 1 - tr[p].sum;
}
void pushdown( int p ) {
	if( tr[p].lz ) {
		uplz( p << 1 );
		uplz( ( p << 1 ) + 1 );
		tr[p].lz = 0;
	}
}
void modify( int p , int l , int r ) {
	if( tr[p].L > r || tr[p].R < l ) {
		return;
	}
	if( tr[p].L >= l && tr[p].R <= r ) {
		uplz( p );
		return;
	}
	pushdown( p );
	modify( p << 1 , l , r );
	modify( ( p << 1 ) + 1 , l , r );
	tr[p].sum = tr[p << 1].sum + tr[( p << 1 ) + 1].sum;
}
int query( int p , int a , int b ) {
	if( tr[p].L > b || tr[p].R < a ) {
		return 0;
	}
	if( tr[p].L >= a && tr[p].R <= b ) {
		return tr[p].sum;
	}
	int sum = 0;
	pushdown( p );
	sum += query( p << 1 , a , b );
	sum += query( ( p << 1 ) + 1 , a , b );
	return sum;
}
signed main() {
	cin >> n >> m;
	build( 1 , 1 , n );
	while( m-- ) {
		int op;
		int x , y;
		cin >> op;
		cin >> x >> y;
		if( op == 0 ) {
			modify( 1 , x , y );
		} else {
			cout << query( 1 , x , y ) << '\n';
		}
	}
	return 0;
}
